SELECT DISTINCT h.*
FROM hotel h
JOIN room_type rt ON rt.hotel_id = h.id
JOIN room_type_inventory i ON i.room_type_id = rt.id




            AND i.date BETWEEN #{startDate} AND #{endDate}


            AND i.date = #{today}





        AND h.l_dong_regn_cd = #{lDongRegnCd}


        AND h.l_dong_signgu_cd = #{lDongSignguCd}




        AND h.id > #{cursorId}


ORDER BY h.id ASC
LIMIT #{size}
